var dialog={init:function(){},actionDialog:function(c,d,a,b){$("#i_dialog .modal-dialog").removeClass("modal-lg").removeClass("modal-sm");if(a===undefined){a=""}if(b!==undefined){$("#i_dialog .modal-dialog").addClass(b)}if(typeof(d)!="object"){d={}}if(Array.isArray(d)){d={}}d.action=c;$.ajax({type:"post",dataType:"json",data:d,url:a,beforeSend:function(){$("#i_dialog").modal("show");$("#i_dialog_data").hide();$("#i_dialog_error").hide();$("#i_dialog_progress").show()},complete:function(){$("#i_dialog_progress").hide()},error:function(){$("#i_dialog_error").html('<div class="alert alert-danger">Не удалось выполнить запрос.</div>').show()},success:function(e){if(e.success){$("#i_dialog_error").hide();$("#i_dialog_label").html(e.title);$("#i_dialog_data").html(e.html).show()}else{$("#i_dialog_data").hide();$("#i_dialog_error").html('<div class="alert alert-danger">'+e.errorText+"</div>").show()}}})}};$(document).ready(function(){dialog.init()});